void selection_sort(int *a, long len){
 for(long i = len-1; i > 0; --i){
 long max_index = i;
 for(long j = len-1; j >= 0; --j){
 if(a[max_index] < a[j]){
 max_index = j;
 }
 }
 int temp = a[i];
 a[i] = a[max_index];
 a[max_index] = temp;
 }

}
